// Filtrar apenas inadimplentes elegíveis para disparo
const hoje = new Date();
hoje.setHours(0, 0, 0, 0);

const elegíveis = [];
const logs = [];

for (const item of $input.all()) {
  const row = item.json;

  // Pular se blacklist
  if (row.nao_contatar === 'TRUE' || row.nao_contatar === true) {
    logs.push(`SKIP (blacklist): ${row.nome_membro}`);
    continue;
  }

  // Pular se já encerrado ou pago
  if (['encerrado', 'pago', 'em_dia'].includes(row.status_pagamento)) {
    continue;
  }

  // Calcular dias em atraso
  const vencimento = new Date(row.data_vencimento);
  vencimento.setHours(0, 0, 0, 0);
  const diasAtraso = Math.floor((hoje - vencimento) / (1000 * 60 * 60 * 24));

  if (diasAtraso < 3) continue; // Ainda não elegível

  // Determinar fase
  let fasePróxima = null;
  const faseAtual = row.fase_cobranca || '';

  if (diasAtraso >= 3  && !faseAtual)           fasePróxima = 'D3';
  if (diasAtraso >= 7  && faseAtual === 'D3')   fasePróxima = 'D7';
  if (diasAtraso >= 15 && faseAtual === 'D7')   fasePróxima = 'D15';
  if (diasAtraso > 15  && faseAtual === 'D15')  fasePróxima = 'encerrado';

  if (!fasePróxima) continue;

  elegíveis.push({
    ...row,
    diasAtraso,
    fasePróxima,
    rowIndex: item.json.__rowIndex || 0
  });
}

console.log(`Elegíveis para disparo: ${elegíveis.length} | Logs: ${logs.join(', ')}`);

// Limitar a 100 por dia
const limitados = elegíveis.slice(0, 100);
return limitados.map(r => ({ json: r }));

const row = $input.first().json;
const nome = row.nome_membro || 'Cliente';
const valor = parseFloat(row.valor_mensalidade || 0).toFixed(2).replace('.', ',');
const fase = row.fasePróxima;

const mensagens = {
  D3: `Oi ${nome}, tudo bem? Aqui é a Karine da SST Card 😊 Identifiquei que sua mensalidade de R$${valor} está em aberto. Pode ser esquecimento — acontece! Pode me confirmar quando consegue regularizar? Pix, débito ou dinheiro na clínica, o que for mais fácil pra você.`,

  D7: `${nome}, já são 7 dias com o cartão suspenso. Não quero te perder como membro! O que aconteceu? Me conta e a gente resolve. A SST Card continua aqui por você — só precisamos que o pagamento de R$${valor} seja regularizado pra reativar o acesso.`,

  D15: `${nome}, última tentativa antes de encerrar sua conta SST Card. Passaram 15 dias de atraso. Se quiser manter o cartão, regularize R$${valor} hoje. Se tiver algum problema financeiro, me fala — a gente pode negociar. Caso não queira continuar, me avisa que encerro sem cobranças futuras.`
};

const texto = mensagens[fase] || mensagens.D3;

return [{ json: { ...row, mensagem: texto } }];

// Escalada para Karine — este membro deve ser encerrado
const row = $input.first().json;
console.warn(`ENCERRAR: ${row.nome_membro} | WhatsApp: ${row.whatsapp} | Atraso: ${row.diasAtraso} dias`);

// Aqui pode adicionar notificação para Karine via Telegram/WhatsApp se necessário
return [{ json: { acao: 'encerrar', membro: row.nome_membro, whatsapp: row.whatsapp, diasAtraso: row.diasAtraso } }];
